mapper.sql:
SELECT ID, USER_ID, ACC_NO, USER_NAME, POST, DEPT, COMPANY_NAME, LOGIN_TIME, LOGIN_IP, CHANNEL_TYPE, UQ_MARK, OS, BROWSER, LOCATION, STATUS, ERROR_MSG FROM SYS_LOGIN_LOG
and ACC_NO = #{accNo}
AND TO_CHAR(LOGIN_TIME, 'YYYY-MM-DD') >= #{beginTimes}
AND TO_CHAR(LOGIN_TIME, 'YYYY-MM-DD') <= #{endTimes}
and USER_NAME = #{userName}
and POST = #{post}
and DEPT = #{dept}
and COMPANY_NAME = #{companyName}
and STATUS = #{status}
